Here's how to test `DataFetcher` with modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, MockHandler handler) CreateFetcher(
        HttpStatusCode status = HttpStatusCode.OK,
        string content = "response-body",
        TimeSpan? delay = null)
    {
        var handler = new MockHandler(status, content, delay);
        var client = new HttpClient(handler) { BaseAddress = new Uri("https://test.local") };
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    [Timeout(5000)] // safety net — fails the test if it hangs
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var (fetcher, _) = CreateFetcher(content: "hello world");

        var result = await fetcher.FetchAsync(
            "https://test.local/data",
            _testContext.CancellationToken);       // ← cooperative timeout

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://test.local/err",
                _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange — server is slow, but we cancel immediately
        var (fetcher, _) = CreateFetcher(delay: TimeSpan.FromSeconds(30));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://test.local/slow", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_TimeoutViaCancellation_ThrowsBeforeCompleting()
    {
        // Arrange — server takes 30s, we allow only 50ms
        var (fetcher, _) = CreateFetcher(delay: TimeSpan.FromSeconds(30));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://test.local/slow", cts.Token));
    }

    // Minimal test double — no mocking framework needed
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _status;
        private readonly string _content;
        private readonly TimeSpan? _delay;

        public MockHandler(HttpStatusCode status, string content, TimeSpan? delay)
        {
            _status = status;
            _content = content;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay is { } d)
                await Task.Delay(d, cancellationToken); // respects cancellation

            return new HttpResponseMessage(_status)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `[Timeout(5000)]` + `_testContext.CancellationToken` | Cooperative timeout — MSTest cancels the token when time expires, preventing hangs |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type (not `[ExpectedException]`) |
| Pre-cancelled `CancellationTokenSource` | Tests that the method checks cancellation early |
| Short-lived `CancellationTokenSource(ms)` | Simulates a real timeout without waiting 30s |
| `sealed class`, constructor-injected `TestContext` | Modern MSTest 3.x conventions |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over delay and status |

The critical detail: always pass `TestContext.CancellationToken` (or your own `CancellationTokenSource.Token`) into the async call. Without it, `[Timeout]` can't cooperatively cancel the work and the test may hang.
